import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { authService } from '../services/api';
import { toast } from 'react-hot-toast';
import { UserRole, RegisterRequest } from '../types';

interface FormData {
  email: string;
  senha: string;
  confirmarSenha: string;
  nome: string;
  papel: UserRole;
  // Campos para instituição de ensino
  tipo?: string;
  areas_ensino?: string[];
  qtd_alunos?: number;
  // Campos para chefe de empresa
  empresa?: string;
  setor?: string;
  porte?: string;
  areas_atuacao?: string[];
  // Campos comuns e de instituição contratante
  localizacao: string;
  areas_interesse?: string[];
  programas_sociais?: string[];
}

interface FormErrors {
  email?: string;
  senha?: string;
  confirmarSenha?: string;
  nome?: string;
  papel?: string;
  tipo?: string;
  empresa?: string;
  setor?: string;
  porte?: string;
  localizacao?: string;
  areas_ensino?: string;
  qtd_alunos?: string;
  areas_atuacao?: string;
  areas_interesse?: string;
  programas_sociais?: string;
  geral?: string;
}

export default function Cadastro() {
  const [formData, setFormData] = useState<FormData>({
    email: '',
    senha: '',
    confirmarSenha: '',
    nome: '',
    papel: 'instituicao_ensino',
    localizacao: '',
    tipo: '',
    areas_ensino: [],
    qtd_alunos: undefined,
    empresa: '',
    setor: '',
    porte: '',
    areas_atuacao: [],
    areas_interesse: [],
    programas_sociais: []
  });
  const [errors, setErrors] = useState<FormErrors>({});
  const [loading, setLoading] = useState(false);
  const [sucesso, setSucesso] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    
    // Limpar erro do campo quando ele é modificado
    if (errors[name as keyof FormErrors]) {
      setErrors(prev => ({ ...prev, [name]: undefined }));
    }
  };
  
  // Função especial para lidar com arrays (habilidades, interesses, etc)
  const handleArrayChange = (name: string, value: string) => {
    // Converter string em array (vírgulas ou linhas novas)
    // A expressão regular mantém espaços internos dentro dos itens
    const items = value.split(/,|\n/).map(item => item.trim()).filter(item => item);
    
    setFormData(prev => ({ ...prev, [name]: items }));
    
    // Limpar erro do campo quando ele é modificado
    if (errors[name as keyof FormErrors]) {
      setErrors(prev => ({ ...prev, [name]: undefined }));
    }
  };

  const validarFormulario = (): boolean => {
    const newErrors: FormErrors = {};
    let isValid = true;

    // Validações básicas
    if (!formData.email) {
      newErrors.email = 'Email é obrigatório';
      isValid = false;
    } else if (!/\S+@\S+\.\S+/.test(formData.email)) {
      newErrors.email = 'Email inválido';
      isValid = false;
    }

    if (!formData.senha) {
      newErrors.senha = 'Senha é obrigatória';
      isValid = false;
    } else if (formData.senha.length < 6) {
      newErrors.senha = 'Senha deve ter pelo menos 6 caracteres';
      isValid = false;
    }

    if (formData.senha !== formData.confirmarSenha) {
      newErrors.confirmarSenha = 'As senhas não coincidem';
      isValid = false;
    }
    
    if (!formData.nome) {
      newErrors.nome = 'Nome é obrigatório';
      isValid = false;
    }
    
    if (!formData.localizacao) {
      newErrors.localizacao = 'Localização é obrigatória';
      isValid = false;
    }

    // Validações específicas por papel
    if (formData.papel === 'instituicao_ensino') {
      if (!formData.tipo) {
        newErrors.tipo = 'Tipo da instituição é obrigatório';
        isValid = false;
      }
      
      if (!formData.areas_ensino || formData.areas_ensino.length === 0) {
        newErrors.areas_ensino = 'Indique pelo menos uma área de ensino';
        isValid = false;
      }
      
      if (!formData.qtd_alunos) {
        newErrors.qtd_alunos = 'Quantidade de alunos é obrigatória';
        isValid = false;
      }
    }
    
    if (formData.papel === 'chefe_empresa') {
      if (!formData.empresa) {
        newErrors.empresa = 'Nome da empresa é obrigatório';
        isValid = false;
      }
      
      if (!formData.setor) {
        newErrors.setor = 'Setor da empresa é obrigatório';
        isValid = false;
      }
      
      if (!formData.porte) {
        newErrors.porte = 'Porte da empresa é obrigatório';
        isValid = false;
      }
      
      if (!formData.areas_atuacao || formData.areas_atuacao.length === 0) {
        newErrors.areas_atuacao = 'Indique pelo menos uma área de atuação';
        isValid = false;
      }
    }
    
    if (formData.papel === 'instituicao_contratante') {
      if (!formData.areas_interesse || formData.areas_interesse.length === 0) {
        newErrors.areas_interesse = 'Indique pelo menos uma área de interesse';
        isValid = false;
      }
      
      if (!formData.programas_sociais || formData.programas_sociais.length === 0) {
        newErrors.programas_sociais = 'Indique pelo menos um programa social';
        isValid = false;
      }
    }

    setErrors(newErrors);
    return isValid;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (!validarFormulario()) {
      return;
    }
    
    setLoading(true);
    setErrors({});
    
    try {
      // Construir payload de acordo com o papel
      const payload: RegisterRequest = {
        email: formData.email,
        senha: formData.senha,
        nome: formData.nome,
        papel: formData.papel as UserRole,
        localizacao: formData.localizacao,
      };
      
      // Adicionar campos específicos por papel
      if (formData.papel === 'instituicao_ensino') {
        payload.tipo = formData.tipo;
        payload.areas_ensino = formData.areas_ensino;
        payload.qtd_alunos = Number(formData.qtd_alunos);
      } else if (formData.papel === 'chefe_empresa') {
        payload.empresa = formData.empresa;
        payload.setor = formData.setor;
        payload.porte = formData.porte;
        payload.areas_atuacao = formData.areas_atuacao;
      } else if (formData.papel === 'instituicao_contratante') {
        payload.areas_interesse = formData.areas_interesse;
        payload.programas_sociais = formData.programas_sociais;
      }
      
      await authService.registro(payload);
      
      toast.success('Cadastro realizado com sucesso!');
      setSucesso(true);
      
      // Redirecionamento automático após 2 segundos
      setTimeout(() => {
        navigate('/login');
      }, 2000);
    } catch (error: any) {
      console.error('Erro no cadastro:', error);
      
      if (error.response?.data?.erro) {
        setErrors({ geral: error.response.data.erro });
        toast.error(error.response.data.erro);
      } else {
        setErrors({ geral: 'Erro ao conectar com o servidor' });
        toast.error('Erro ao conectar com o servidor');
      }
    } finally {
      setLoading(false);
    }
  };

  // Renderização condicional dos campos baseado no papel selecionado
  const renderCamposEspecificos = () => {
    switch (formData.papel) {
      case 'instituicao_ensino':
        return (
          <>
            <div>
              <label className="block text-cursor-text-tertiary text-sm mb-1">Tipo da Instituição*</label>
              <select
                name="tipo"
                className={`w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border ${
                  errors.tipo ? 'border-red-500' : 'border-cursor-border'
                } focus:border-cursor-primary focus:outline-none`}
                value={formData.tipo}
                onChange={handleChange}
                required
              >
                <option value="">Selecione um tipo</option>
                <option value="Universidade Pública">Universidade Pública</option>
                <option value="Universidade Privada">Universidade Privada</option>
                <option value="Instituto Técnico">Instituto Técnico</option>
                <option value="Escola Técnica">Escola Técnica</option>
                <option value="Escola de Ensino Médio">Escola de Ensino Médio</option>
                <option value="Outra">Outra</option>
              </select>
              {errors.tipo && <p className="text-red-500 text-sm mt-1">{errors.tipo}</p>}
            </div>
            <div>
              <label className="block text-cursor-text-tertiary text-sm mb-1">Áreas de Ensino*</label>
              <textarea
                name="areas_ensino"
                placeholder="Tecnologia, Engenharia, Administração... (separadas por vírgula)"
                className={`w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border ${
                  errors.areas_ensino ? 'border-red-500' : 'border-cursor-border'
                } focus:border-cursor-primary focus:outline-none`}
                value={formData.areas_ensino?.join(', ')}
                onChange={(e) => handleArrayChange('areas_ensino', e.target.value)}
                rows={3}
                required
              />
              {errors.areas_ensino && <p className="text-red-500 text-sm mt-1">{errors.areas_ensino}</p>}
            </div>
            <div>
              <label className="block text-cursor-text-tertiary text-sm mb-1">Quantidade de Alunos*</label>
              <input
                type="number"
                name="qtd_alunos"
                placeholder="Ex: 1000"
                className={`w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border ${
                  errors.qtd_alunos ? 'border-red-500' : 'border-cursor-border'
                } focus:border-cursor-primary focus:outline-none`}
                value={formData.qtd_alunos || ''}
                onChange={handleChange}
                min="1"
                required
              />
              {errors.qtd_alunos && <p className="text-red-500 text-sm mt-1">{errors.qtd_alunos}</p>}
            </div>
          </>
        );
      case 'chefe_empresa':
        return (
          <>
            <div>
              <label className="block text-cursor-text-tertiary text-sm mb-1">Nome da Empresa*</label>
              <input
                type="text"
                name="empresa"
                placeholder="Nome da sua empresa"
                className={`w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border ${
                  errors.empresa ? 'border-red-500' : 'border-cursor-border'
                } focus:border-cursor-primary focus:outline-none`}
                value={formData.empresa}
                onChange={handleChange}
                required
              />
              {errors.empresa && <p className="text-red-500 text-sm mt-1">{errors.empresa}</p>}
            </div>
            <div>
              <label className="block text-cursor-text-tertiary text-sm mb-1">Setor*</label>
              <select
                name="setor"
                className={`w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border ${
                  errors.setor ? 'border-red-500' : 'border-cursor-border'
                } focus:border-cursor-primary focus:outline-none`}
                value={formData.setor}
                onChange={handleChange}
                required
              >
                <option value="">Selecione um setor</option>
                <option value="Tecnologia">Tecnologia</option>
                <option value="Manufatura">Manufatura</option>
                <option value="Serviços">Serviços</option>
                <option value="Comércio">Comércio</option>
                <option value="Educação">Educação</option>
                <option value="Saúde">Saúde</option>
                <option value="Outro">Outro</option>
              </select>
              {errors.setor && <p className="text-red-500 text-sm mt-1">{errors.setor}</p>}
            </div>
            <div>
              <label className="block text-cursor-text-tertiary text-sm mb-1">Porte da Empresa*</label>
              <select
                name="porte"
                className={`w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border ${
                  errors.porte ? 'border-red-500' : 'border-cursor-border'
                } focus:border-cursor-primary focus:outline-none`}
                value={formData.porte}
                onChange={handleChange}
                required
              >
                <option value="">Selecione um porte</option>
                <option value="Micro">Micro</option>
                <option value="Pequeno">Pequeno</option>
                <option value="Médio">Médio</option>
                <option value="Grande">Grande</option>
              </select>
              {errors.porte && <p className="text-red-500 text-sm mt-1">{errors.porte}</p>}
            </div>
            <div>
              <label className="block text-cursor-text-tertiary text-sm mb-1">Áreas de Atuação*</label>
              <textarea
                name="areas_atuacao"
                placeholder="Desenvolvimento de Software, Marketing Digital... (separadas por vírgula)"
                className={`w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border ${
                  errors.areas_atuacao ? 'border-red-500' : 'border-cursor-border'
                } focus:border-cursor-primary focus:outline-none`}
                value={formData.areas_atuacao?.join(', ')}
                onChange={(e) => handleArrayChange('areas_atuacao', e.target.value)}
                rows={3}
                required
              />
              {errors.areas_atuacao && <p className="text-red-500 text-sm mt-1">{errors.areas_atuacao}</p>}
            </div>
          </>
        );
      case 'instituicao_contratante':
        return (
          <>
            <div>
              <label className="block text-cursor-text-tertiary text-sm mb-1">Áreas de Interesse*</label>
              <textarea
                name="areas_interesse"
                placeholder="Tecnologia, Ensino, Administração... (separadas por vírgula)"
                className={`w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border ${
                  errors.areas_interesse ? 'border-red-500' : 'border-cursor-border'
                } focus:border-cursor-primary focus:outline-none`}
                value={formData.areas_interesse?.join(', ')}
                onChange={(e) => handleArrayChange('areas_interesse', e.target.value)}
                rows={3}
                required
              />
              {errors.areas_interesse && <p className="text-red-500 text-sm mt-1">{errors.areas_interesse}</p>}
            </div>
            <div>
              <label className="block text-cursor-text-tertiary text-sm mb-1">Programas Sociais*</label>
              <textarea
                name="programas_sociais"
                placeholder="Jovem Aprendiz, Primeiro Emprego... (separados por vírgula)"
                className={`w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border ${
                  errors.programas_sociais ? 'border-red-500' : 'border-cursor-border'
                } focus:border-cursor-primary focus:outline-none`}
                value={formData.programas_sociais?.join(', ')}
                onChange={(e) => handleArrayChange('programas_sociais', e.target.value)}
                rows={3}
                required
              />
              {errors.programas_sociais && <p className="text-red-500 text-sm mt-1">{errors.programas_sociais}</p>}
            </div>
          </>
        );
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-cursor-bg relative flex items-center justify-center overflow-hidden">
      {/* Background with subtle gradient */}
      <div className="absolute inset-0 z-0">
        <div className="absolute inset-0 bg-gradient-to-b from-cursor-bg-lighter to-cursor-bg opacity-40"></div>
      </div>
      
      {/* Animated blurred blobs */}
      <div className="absolute top-1/4 left-1/3 w-64 h-64 bg-cursor-primary/20 rounded-full filter blur-3xl opacity-20 animate-blob"></div>
      <div className="absolute bottom-1/4 right-1/3 w-72 h-72 bg-cursor-accent/20 rounded-full filter blur-3xl opacity-20 animate-blob animation-delay-2000"></div>
      
      {/* Content */}
      <div className="relative z-10 max-w-md w-full px-4 py-8">
        <div className="text-center mb-8">
          <h1 className="text-3xl font-bold">
            <span className="bg-gradient-to-r from-cursor-primary to-cursor-accent bg-clip-text text-transparent">
              TalentBridge
            </span>
          </h1>
        </div>
        
        <div className="bg-cursor-bg-light border border-cursor-border rounded-xl p-6 shadow-cursor animate-fade-in">
          {sucesso ? (
            <div className="text-center py-8">
              <div className="h-16 w-16 mx-auto rounded-full bg-cursor-primary/20 flex items-center justify-center mb-4">
                <svg className="h-8 w-8 text-cursor-primary" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                </svg>
              </div>
              <h2 className="text-2xl font-medium text-cursor-text-primary mb-3">Cadastro Realizado!</h2>
              <p className="text-cursor-text-secondary mb-2">Sua conta foi criada com sucesso.</p>
              <p className="text-cursor-text-tertiary">Redirecionando para o login...</p>
            </div>
          ) : (
            <>
              <h2 className="text-2xl font-medium text-cursor-text-primary mb-6">Cadastro</h2>
              
              <form onSubmit={handleSubmit} className="space-y-5">
                <div>
                  <label className="block text-cursor-text-tertiary text-sm mb-1">Tipo de Usuário*</label>
                  <select
                    name="papel"
                    className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:outline-none"
                    value={formData.papel}
                    onChange={handleChange}
                  >
                    <option value="instituicao_ensino">Instituição de Ensino</option>
                    <option value="chefe_empresa">Chefe de Empresa</option>
                    <option value="instituicao_contratante">Instituição Contratante</option>
                  </select>
                </div>
                
                <div>
                  <label className="block text-cursor-text-tertiary text-sm mb-1">Nome*</label>
                  <input
                    type="text"
                    name="nome"
                    placeholder="Nome completo ou nome da instituição"
                    className={`w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border ${
                      errors.nome ? 'border-red-500' : 'border-cursor-border'
                    } focus:border-cursor-primary focus:outline-none`}
                    value={formData.nome}
                    onChange={handleChange}
                    required
                  />
                  {errors.nome && <p className="text-red-500 text-sm mt-1">{errors.nome}</p>}
                </div>
                
                <div>
                  <label className="block text-cursor-text-tertiary text-sm mb-1">Email*</label>
                  <input
                    type="email"
                    name="email"
                    placeholder="email@exemplo.com"
                    className={`w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border ${
                      errors.email ? 'border-red-500' : 'border-cursor-border'
                    } focus:border-cursor-primary focus:outline-none`}
                    value={formData.email}
                    onChange={handleChange}
                    required
                  />
                  {errors.email && <p className="text-red-500 text-sm mt-1">{errors.email}</p>}
                </div>
                
                <div>
                  <label className="block text-cursor-text-tertiary text-sm mb-1">Localização*</label>
                  <input
                    type="text"
                    name="localizacao"
                    placeholder="Cidade, Estado"
                    className={`w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border ${
                      errors.localizacao ? 'border-red-500' : 'border-cursor-border'
                    } focus:border-cursor-primary focus:outline-none`}
                    value={formData.localizacao}
                    onChange={handleChange}
                    required
                  />
                  {errors.localizacao && <p className="text-red-500 text-sm mt-1">{errors.localizacao}</p>}
                </div>
                
                {/* Campos específicos para cada papel */}
                {renderCamposEspecificos()}
                
                <div>
                  <label className="block text-cursor-text-tertiary text-sm mb-1">Senha*</label>
                  <input
                    type="password"
                    name="senha"
                    placeholder="••••••••"
                    className={`w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border ${
                      errors.senha ? 'border-red-500' : 'border-cursor-border'
                    } focus:border-cursor-primary focus:outline-none`}
                    value={formData.senha}
                    onChange={handleChange}
                    required
                    minLength={6}
                  />
                  {errors.senha && <p className="text-red-500 text-sm mt-1">{errors.senha}</p>}
                </div>
                
                <div>
                  <label className="block text-cursor-text-tertiary text-sm mb-1">Confirmar Senha*</label>
                  <input
                    type="password"
                    name="confirmarSenha"
                    placeholder="••••••••"
                    className={`w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border ${
                      errors.confirmarSenha ? 'border-red-500' : 'border-cursor-border'
                    } focus:border-cursor-primary focus:outline-none`}
                    value={formData.confirmarSenha}
                    onChange={handleChange}
                    required
                  />
                  {errors.confirmarSenha && <p className="text-red-500 text-sm mt-1">{errors.confirmarSenha}</p>}
                </div>
                
                {errors.geral && (
                  <div className="p-3 bg-red-500/10 border border-red-500/30 rounded-lg">
                    <p className="text-red-500 text-sm">{errors.geral}</p>
                  </div>
                )}
                
                <button 
                  type="submit" 
                  className="w-full p-3 rounded-lg bg-cursor-primary hover:bg-cursor-primary-dark text-white font-medium transition-colors"
                  disabled={loading}
                >
                  {loading ? (
                    <span className="flex items-center justify-center">
                      <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                      </svg>
                      Cadastrando...
                    </span>
                  ) : 'Cadastrar'}
                </button>
              </form>
              
              <div className="mt-6 text-center">
                <p className="text-cursor-text-secondary">
                  Já tem conta?{' '}
                  <Link to="/login" className="text-cursor-primary hover:underline">
                    Faça login
                  </Link>
                </p>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
